import "./context-menu.css";

import { ContextMenu } from "radix-ui";

import { ContextMenuContext } from "./context-menu.context";
import { contextMenuVariants } from "./context-menu.variants";

export type ContextMenuRootProps = React.ComponentProps<typeof ContextMenu.Root>;

export const ContextMenuRoot = (props: ContextMenuRootProps) => {
  const slots = contextMenuVariants();

  return (
    <ContextMenuContext value={{ slots }}>
      <ContextMenu.Root {...props} />
    </ContextMenuContext>
  );
};

import { ContextMenu } from "radix-ui";

export type ContextMenuTriggerProps = React.ComponentProps<typeof ContextMenu.Trigger>;

export const ContextMenuTrigger = (props: ContextMenuTriggerProps) => {
  return <ContextMenu.Trigger {...props} />;
};

import { ContextMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useContextMenuContext } from "./context-menu.context";

export type ContextMenuContentProps = React.ComponentProps<typeof ContextMenu.Content>;

export const ContextMenuContent = ({ className, ...props }: ContextMenuContentProps) => {
  const { slots } = useContextMenuContext();

  return (
    <ContextMenu.Portal>
      <ContextMenu.Content className={cn(slots.content(), className)} {...props} />
    </ContextMenu.Portal>
  );
};

