import { createContext, useContext } from "react";

import { contextMenuVariants } from "./context-menu.variants";

export type ContextMenuContext = {
  slots: ReturnType<typeof contextMenuVariants>;
};

export const ContextMenuContext = createContext<ContextMenuContext | null>(null);

export const useContextMenuContext = () => {
  const context = useContext(ContextMenuContext);
  if (!context) {
    throw new Error("useContextMenuContext must be used within a ContextMenu");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const contextMenuVariants = tv({
  slots: {
    checkbox: "context-menu__checkbox-item",
    content: "context-menu__content",
    indicator: "context-menu__indicator",
    item: "context-menu__item",
    label: "context-menu__label",
    radio: "context-menu__radio-item",
    separator: "context-menu__separator",
    shortcut: "context-menu__shortcut",
    subContent: "context-menu__sub-content",
    subTrigger: "context-menu__sub-trigger",
  },
});

export type ContextMenuVariants = VariantProps<typeof contextMenuVariants>;

.context-menu__content {
  @apply bg-popover text-popover-foreground z-50 min-w-[8rem] overflow-hidden rounded-md border p-1 shadow-md;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }
}

.context-menu__item {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.context-menu__checkbox-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.context-menu__radio-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.context-menu__indicator {
  @apply absolute left-2 inline-flex items-center justify-center;

  & svg {
    @apply size-3.5;
  }
}

.context-menu__label {
  @apply text-muted-foreground px-2 py-1.5 text-xs font-semibold;
}

.context-menu__separator {
  @apply bg-border -mx-1 my-1 h-px;
}

.context-menu__shortcut {
  @apply text-muted-foreground ml-auto text-xs tracking-widest;
}

.context-menu__sub-trigger {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-state="open"] {
    @apply bg-accent text-accent-foreground;
  }
}

.context-menu__sub-content {
  @apply bg-popover text-popover-foreground z-50 min-w-[8rem] overflow-hidden rounded-md border p-1 shadow-lg;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }
}

import { ContextMenuCheckboxItem } from "./context-menu-checkbox-item";
import { ContextMenuContent } from "./context-menu-content";
import { ContextMenuItem } from "./context-menu-item";
import { ContextMenuLabel } from "./context-menu-label";
import { ContextMenuRadioItem } from "./context-menu-radio-item";
import { ContextMenuRoot } from "./context-menu-root";
import { ContextMenuSeparator } from "./context-menu-separator";
import { ContextMenuShortcut } from "./context-menu-shortcut";
import { ContextMenuSub, ContextMenuSubContent, ContextMenuSubTrigger } from "./context-menu-sub";
import { ContextMenuTrigger } from "./context-menu-trigger";

export const ContextMenu = {
  CheckboxItem: ContextMenuCheckboxItem,
  Content: ContextMenuContent,
  Item: ContextMenuItem,
  Label: ContextMenuLabel,
  RadioItem: ContextMenuRadioItem,
  Root: ContextMenuRoot,
  Separator: ContextMenuSeparator,
  Shortcut: ContextMenuShortcut,
  Sub: ContextMenuSub,
  SubContent: ContextMenuSubContent,
  SubTrigger: ContextMenuSubTrigger,
  Trigger: ContextMenuTrigger,
};

export {
  ContextMenuCheckboxItem,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuRadioItem,
  ContextMenuRoot,
  ContextMenuSeparator,
  ContextMenuShortcut,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
  ContextMenuTrigger,
};

export type { ContextMenuCheckboxItemProps } from "./context-menu-checkbox-item";

export type { ContextMenuContentProps } from "./context-menu-content";

export type { ContextMenuItemProps } from "./context-menu-item";
export type { ContextMenuLabelProps } from "./context-menu-label";
export type { ContextMenuRadioItemProps } from "./context-menu-radio-item";
export type { ContextMenuRootProps } from "./context-menu-root";
export type { ContextMenuSeparatorProps } from "./context-menu-separator";
export type { ContextMenuShortcutProps } from "./context-menu-shortcut";
export type {
  ContextMenuSubContentProps,
  ContextMenuSubProps,
  ContextMenuSubTriggerProps,
} from "./context-menu-sub";
export type { ContextMenuTriggerProps } from "./context-menu-trigger";
export { ContextMenuContext, useContextMenuContext } from "./context-menu.context";
export { type ContextMenuVariants, contextMenuVariants } from "./context-menu.variants";
